+    .col-review .col-header { background: rgba(176,106,240,0.08); color: var(--purple); border-bottom-color: #2a1050; }
+    .col-marcus .col-header { background: rgba(255,176,0,0.08); color: var(--amber); border-bottom-color: #3a2a00; }
+    .col-discuss .col-header { background: rgba(57,255,20,0.05); color: var(--text-dim); border-bottom-color: var(--border); }
+    .col-backlog .col-header { background: rgba(57,255,20,0.03); color: var(--text-dim); border-bottom-color: var(--border); }
