+    .label-crunch-research { color: #4af; border-color: #0a2a4a; background: rgba(74,170,255,0.06); }
+    .label-crunch-proposal { color: #a4f; border-color: #2a1050; background: rgba(130,80,240,0.06); }
+    .label-crunch-heartbeat{ color: var(--green-dim); border-color: var(--border); background: transparent; }
