+<body>
+<div class="container">
+
+  <div class="header">
+    <div class="header-left">
+      <div>
+        <div class="header-title">🦃 CRUNCH — KANBAN</div>
+        <div class="header-sub"><span class="pulse-dot"></span> live · Copilotclaw/copilotclaw</div>
+      </div>
+    </div>
+    <nav class="nav">
+      <a href="index.html">home</a>
+      <a href="kanban.html" class="active">kanban</a>
+      <a href="https://github.com/Copilotclaw/copilotclaw/issues" target="_blank">issues ↗</a>
+    </nav>
+  </div>
+
+  <div id="status">⟳ loading issues…</div>
+  <div class="board" id="board" style="display:none"></div>
+
+  <div class="footer">
+    <a href="index.html">← home</a>
+    &nbsp;·&nbsp;
+    <a href="https://github.com/Copilotclaw/copilotclaw">github.com/Copilotclaw/copilotclaw</a>
+    &nbsp;·&nbsp;
+    <span id="loaded-at"></span>
+    &nbsp;·&nbsp;
+    🦃 crunch
+  </div>
+
+</div>
+
+<script>
+const REPO = 'Copilotclaw/copilotclaw';
+const API  = `https://api.github.com/repos/${REPO}/issues?state=open&per_page=100`;
+
+// Column definitions — order matters, first match wins
+const COLUMNS = [
+  { id: 'now',     title: '🔥 Now',      match: i => hasLabel(i, 'priority/now') },
+  { id: 'marcus',  title: '📌 Marcus',   match: i => hasLabel(i, 'marcus/todo') },
+  { id: 'build',   title: '🔨 Building', match: i => hasLabel(i, 'crunch/build') },
+  { id: 'review',  title: '👀 Review',   match: i => hasLabel(i, 'crunch/review') },
+  { id: 'discuss', title: '💬 Discuss',  match: i => hasLabel(i, 'crunch/discuss') || hasLabel(i, 'crunch/proposal') || hasLabel(i, 'crunch/research') },
+  { id: 'backlog', title: '📥 Backlog',  match: () => true },
+];
+
+function hasLabel(issue, name) {
+  return issue.labels.some(l => l.name === name);
+}
+
+function labelClass(name) {
+  const map = {
+    'priority/now':      'priority-now',
+    'priority/soon':     'priority-soon',
+    'priority/someday':  'priority-someday',
+    'crunch/build':      'crunch-build',
+    'crunch/review':     'crunch-review',
+    'crunch/discuss':    'crunch-discuss',
+    'crunch/research':   'crunch-research',
+    'crunch/proposal':   'crunch-proposal',
+    'crunch/heartbeat':  'crunch-heartbeat',
+    'marcus/todo':       'marcus-todo',
+  };
+  return 'label label-' + (map[name] || 'default');
+}
+
+function renderCard(issue) {
+  const labels = issue.labels
+    .filter(l => l.name !== 'priority/now') // don't re-show col label
+    .map(l => `<span class="${labelClass(l.name)}">${l.name}</span>`)
+    .join('');
+
+  // Strip emoji prefixes like "🔧 [crunch/build] "
+  const title = issue.title.replace(/^[^\w\s]+\s*(\[.*?\]\s*)?/, '');
+
+  return `
+    <div class="card" onclick="window.open('${issue.html_url}','_blank')">
+      <div class="card-num">#${issue.number}</div>
+      <div class="card-title">${escHtml(title)}</div>
+      ${labels ? `<div class="card-labels">${labels}</div>` : ''}
+    </div>`;
+}
+
+function escHtml(s) {
+  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
+}
+
+async function load() {
+  try {
+    const res = await fetch(API, { headers: { 'Accept': 'application/vnd.github+json' } });
+    if (!res.ok) throw new Error(`GitHub API ${res.status}`);
+    const issues = await res.json();
+
+    // filter out pull requests
+    const realIssues = issues.filter(i => !i.pull_request);
+
+    // bucket into columns
+    const buckets = {};
+    COLUMNS.forEach(c => buckets[c.id] = []);
+    realIssues.forEach(issue => {
+      for (const col of COLUMNS) {
+        if (col.match(issue)) { buckets[col.id].push(issue); break; }
+      }
+    });
+
+    const board = document.getElementById('board');
+    board.innerHTML = COLUMNS.map(col => {
+      const items = buckets[col.id];
+      const cards = items.length
+        ? items.map(renderCard).join('')
+        : `<div class="empty">—</div>`;
+      return `
+        <div class="column col-${col.id}">
+          <div class="col-header">
+            <span class="col-title">${col.title}</span>
+            <span class="col-count">${items.length}</span>
+          </div>
+          <div class="col-body">${cards}</div>
+        </div>`;
+    }).join('');
+
+    document.getElementById('status').style.display = 'none';
+    board.style.display = 'grid';
+
+    const now = new Date();
+    document.getElementById('loaded-at').textContent =
+      'loaded ' + now.toISOString().replace('T',' ').slice(0,19) + ' UTC';
+  } catch (e) {
+    document.getElementById('status').innerHTML =
+      `⚠ failed to load issues: ${escHtml(e.message)}<br><small>GitHub API rate-limits unauthenticated requests to 60/hour</small>`;
+  }
+}
+
+load();
+</script>
+</body>
+</html>
+
